import{_ as i}from"./chunks/FetchSearch.vue_vue_type_script_setup_true_lang.DaazAy6s.js";import{T as n}from"./chunks/ZigenTrain.DpW6WAfw.js";import{Z as r}from"./chunks/ZigenMap.Bb3_mnCU.js";import{S as d,j as s,m as g,g as e,o as l,n as a}from"./chunks/framework.bs_IcUcR.js";import"./chunks/share.mReafxuL.js";import"./chunks/html2canvas-pro.esm.C7wW9koE.js";import"./chunks/advancedSchedule.CyVEQGBC.js";import"./chunks/cascadeStyles.8DEVsCxs.js";/* empty css                                                                          */const o={class:"zigen-font"},f={class:"zigen-font"},v=JSON.parse('{"title":"月靈","description":"","frontmatter":{"aside":false},"headers":[],"relativePath":"zht/ime/yueling.md","filePath":"zht/ime/yueling.md"}'),h={name:"zht/ime/yueling.md"},P=Object.assign(h,{setup(y){return(u,t)=>(d(),s("div",null,[t[0]||(t[0]=g('<h1 id="月靈" tabindex="-1">月靈 <a class="header-anchor" href="#月靈" aria-label="Permalink to &quot;月靈&quot;">​</a></h1><h2 id="簡介" tabindex="-1">簡介 <a class="header-anchor" href="#簡介" aria-label="Permalink to &quot;簡介&quot;">​</a></h2><p><a href="https://github.com/PillowMonth/yueling-ime" target="_blank" rel="noreferrer">月靈</a>輸入方案是以靈明爲基礎，專爲簡體性能優化的方案。結合了 90% <a href="https://shurufa.app/docs/ling.html" target="_blank" rel="noreferrer">靈明</a>和 10% <a href="https://shurufa.app/docs/ming.html" target="_blank" rel="noreferrer">日月</a>的設計：</p><ol><li>參照日月、靈明，使用 25 鍵方案，聲母 z/zh 用 v 代替，ch 聲碼爲 c，sh 聲碼爲 s，零聲母用 j 代替，另外聲母 q 用 k 代替以降低 q 鍵壓力；</li><li>字根聚類程度接近靈明；</li><li>大根聲碼與靈明相同，字根韻碼類日月映射至 A、E、U、I、O，单元音除 ü -&gt; O，其余不变，无读音 Ø -&gt; E，記憶壓力較原版靈明稍高；</li><li>爲簡體字頻優化，簡體字頻全碼當量及簡體動重大幅降低，繁體動重較高；</li><li>單字編碼規則同靈明，編碼限長四碼；</li></ol><p>月靈方案的設計初衷，源於靈明為兼顧簡繁通打而犧牲了部分簡體性能，同時靈明為降低學習門檻，採用了以韻腹為核心的韻碼取碼策略，致使當量難以進一步壓縮。月靈雖然在簡體動態重碼率與當量方面有所精進，但在易學難忘性、繁體靜態重碼數及繁體動態重碼率等指標上，仍遠遜於靈明。因此，月靈並不推薦給一般用戶或需要輸入繁體的使用者，僅適合那些僅有簡體輸入需求、且對性能有極致追求的用戶。對自定碼感興趣的普通用戶及形碼初學者，建議學習宇浩輸入法系列中的「日月」與「靈明」方案。</p><p>使用<a href="https://ceping.shurufa.app" target="_blank" rel="noreferrer">宇浩測評</a>測得的性能指標：</p><ul><li>通用規範 8105 字靜重： 296 非首選字；</li><li>常用國字 4808 字靜重： 101 非首選字；</li><li>知乎簡體·頻率降序動重： 1.12‱；</li><li>北語簡體·頻率降序動重： 1.77‱；</li><li>臺標繁體·頻率降序動重： 32.06‱；</li><li>知乎簡體字頻全碼當量： 1.2453；</li><li>北語簡體字頻全碼當量： 1.2467；</li><li>臺標繁體字頻全碼當量： 1.2909；</li><li>簡碼效率： 北語字頻 50 簡碼 3.087，100 簡碼 2.971，所有簡碼 2.736；</li></ul><h2 id="映射" tabindex="-1">映射 <a class="header-anchor" href="#映射" aria-label="Permalink to &quot;映射&quot;">​</a></h2><table><thead><tr><th style="text-align:left;">A</th><th style="text-align:left;">E</th><th style="text-align:left;">U</th><th style="text-align:left;">I</th><th style="text-align:left;">O</th></tr></thead><tbody><tr><td style="text-align:left;">a</td><td style="text-align:left;">e Ø</td><td style="text-align:left;">u</td><td style="text-align:left;">i</td><td style="text-align:left;">o ü</td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;">ao</td><td style="text-align:left;"></td><td style="text-align:left;"></td><td style="text-align:left;">ai</td></tr><tr><td style="text-align:left;">er</td><td style="text-align:left;"></td><td style="text-align:left;"></td><td style="text-align:left;"></td><td style="text-align:left;">ei</td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;">(k)ua üe uo</td><td style="text-align:left;">ua</td><td style="text-align:left;"></td><td style="text-align:left;">uei</td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;">ie</td><td style="text-align:left;"></td><td style="text-align:left;">ia</td><td style="text-align:left;">iao iou</td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"></td><td style="text-align:left;"></td><td style="text-align:left;">ou</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;">en ian</td><td style="text-align:left;"></td><td style="text-align:left;">an</td><td style="text-align:left;"></td><td style="text-align:left;">in uan uen iuan</td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;">ong</td><td style="text-align:left;">eng ing</td><td style="text-align:left;"></td><td style="text-align:left;">ang</td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;">uang</td><td style="text-align:left;"></td><td style="text-align:left;">iang</td><td style="text-align:left;">iong</td></tr></tbody></table><p>特別注意：</p><ul><li>q 聲母映射至 k ，z 聲母映射至 v ，零聲母聲碼爲 j；</li><li>w 、y 聲母不變，僅“肀”：yù，聲碼取零聲母聲碼 j（yu = ü），全碼爲：gjo；</li><li>當聲碼爲 k 時，韻母 ua 映射至 e，僅“㐄”、“𰀁”：dke；</li><li>“夂”、“攵”、“夊”歸併後，聲碼取：夂[zh]ǐ → v，韻碼取：攵p[ū] → u，全碼爲 mvu；</li></ul><h2 id="致謝" tabindex="-1">致謝 <a class="header-anchor" href="#致謝" aria-label="Permalink to &quot;致謝&quot;">​</a></h2><ul><li>感謝朱宇浩製作的優質拆分和日月、靈明優質方案；</li><li>感謝 <a href="https://github.com/hertz-hwang" target="_blank" rel="noreferrer">@荒</a> 的<a href="https://github.com/hertz-hwang/code_genie" target="_blank" rel="noreferrer">碼靈</a>優化程序；</li><li>感謝上述兩位作者的討論和指導，以及羣友及魔靈製作者 <a href="https://github.com/Dieken" target="_blank" rel="noreferrer">@qq3qq</a> 的多次指導与啓發；</li></ul><h2 id="拆分" tabindex="-1">拆分 <a class="header-anchor" href="#拆分" aria-label="Permalink to &quot;拆分&quot;">​</a></h2>',14)),e("div",o,[l(i,{chaifenUrl:"/chaifen.json",zigenUrl:"/zigen-yueling.csv",rule:"ling"})]),t[1]||(t[1]=e("h2",{id:"字根",tabindex:"-1"},[a("字根 "),e("a",{class:"header-anchor",href:"#字根","aria-label":'Permalink to "字根"'},"​")],-1)),l(r,{"default-scheme":"yueling",alwaysVisibleZigens:"卩丂丩屮丱髟廾豕彡",chaifenUrl:"/chaifen.json","column-min-width":"1rem",schemeCnName:"月靈",customFooter:"QQ羣: 544760766 · 本圖鏈接: https://shurufa.app/ime/yueling"}),t[2]||(t[2]=e("h2",{id:"練習",tabindex:"-1"},[a("練習 "),e("a",{class:"header-anchor",href:"#練習","aria-label":'Permalink to "練習"'},"​")],-1)),e("div",f,[l(n,{name:"yueling",chaifenUrl:"/chaifen.json",zigenUrl:"/zigen-yueling.csv",range:[0],mode:"both",rule:"ling"})])]))}});export{v as __pageData,P as default};
